const input = $input.first().json;

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.openclaw&select=cred_key,cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0) {
  return [{ json: { error: 'OpenClaw credentials not configured. Use add_credential to set them up.' } }];
}

const gatewayUrl = (creds.find(c => c.cred_key === 'openclaw_url')?.cred_value || '').replace(/\/$/, '');
const token = creds.find(c => c.cred_key === 'openclaw_token')?.cred_value;

if (!gatewayUrl || !token) {
  return [{ json: { error: 'OpenClaw Gateway URL and token are both required. Use add_credential to configure them.' } }];
}

const message = input.message;
if (!message) {
  return [{ json: { error: 'Parameter "message" is required.' } }];
}

const model = (input.model && input.model !== '') ? input.model : 'openclaw:main';
const callerId = creds.find(c => c.cred_key === 'openclaw_caller_id')?.cred_value || 'n8n-claw';

try {
  const messages = [{ role: 'user', content: message }];

  // Add system message if provided
  if (input.system_message && input.system_message !== '') {
    messages.unshift({ role: 'system', content: input.system_message });
  }

  const resp = await helpers.httpRequest({
    method: 'POST',
    url: gatewayUrl + '/v1/chat/completions',
    headers: {
      'Authorization': 'Bearer ' + token,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: model,
      messages: messages,
      user: callerId
    }),
    timeout: 120000
  });

  const parsed = typeof resp === 'string' ? JSON.parse(resp) : resp;

  if (parsed.error) {
    return [{ json: { error: 'OpenClaw error: ' + (parsed.error.message || JSON.stringify(parsed.error)) } }];
  }

  const choice = parsed.choices && parsed.choices[0];
  if (!choice) {
    return [{ json: { error: 'No response from OpenClaw agent.' } }];
  }

  const content = choice.message?.content || '(empty response)';
  let result = '**Response from OpenClaw agent:**\n\n' + content;

  if (parsed.usage) {
    result += '\n\n(Tokens: ' + (parsed.usage.total_tokens || '?') + ')';
  }

  return [{ json: { result } }];
} catch (err) {
  return [{ json: { error: 'Failed to reach OpenClaw instance: ' + err.message } }];
}
